let map;const dataElement=document.getElementById("map-data");if(dataElement){const mapData=JSON.parse(dataElement.textContent),{lat:lat,lng:lng,location_name:location_name}=mapData;function waitForGoogleMaps(callback){window.google&&window.google.maps&&"function"==typeof google.maps.Map?callback():setTimeout((()=>waitForGoogleMaps(callback)),100)}function initMap(){const mapContainer=document.getElementById("map-container");map=new google.maps.Map(mapContainer,{scrollwheel:!1,draggable:!0,disableDoubleClickZoom:!0,zoomControl:!1,zoom:16,center:{lat:lat,lng:lng},styles:InsitesUtil.getTheme()}),new google.maps.Marker({position:{lat:lat,lng:lng},map:map,title:location_name})}document.addEventListener("DOMContentLoaded",(()=>{waitForGoogleMaps(initMap)}))}